-- {"operators": "INNER_JOIN,AGGREGATE,FILTER,CTE,SUBQUERY", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
WITH base AS (SELECT OL_W_ID, OL_D_ID, OL_O_ID, SUM(OL_AMOUNT) AS total FROM dl.ORDER_LINE GROUP BY OL_W_ID, OL_D_ID, OL_O_ID), top_orders AS (SELECT OL_W_ID, OL_D_ID, OL_O_ID FROM base WHERE total > 50) SELECT o.O_W_ID, o.O_ID, c.C_LAST FROM dl.OORDER o JOIN top_orders t ON o.O_W_ID = t.OL_W_ID AND o.O_D_ID = t.OL_D_ID AND o.O_ID = t.OL_O_ID JOIN dl.CUSTOMER c ON o.O_W_ID = c.C_W_ID AND o.O_D_ID = c.C_D_ID AND o.O_C_ID = c.C_ID;
